import java.util.*;
public class Checker {
    public static boolean hasCycle(int[][] g) {
        // messy graph cycle check
        int n = g.length;
        int[] v = new int[n];
        for(int i=0; i<n; i++) {
            if(v[i]==0 && dfs(i, g, v)) return true;
        }
        return false;
    }
    private static boolean dfs(int curr, int[][] g, int[] v) {
        v[curr] = 1; // visiting
        for(int next : g[curr]) {
            if(v[next]==1) return true;
            if(v[next]==0 && dfs(next, g, v)) return true;
        }
        v[curr] = 2; // visited
        return false;
    }
}

/**
 * The CycleDetector class provides utility methods to verify the presence of
 * cyclic dependencies within an unweighted directed graph structure.
 */
public class CycleDetector {

    public static boolean detectCycle(int[][] adjacencyMatrix) {
        if (adjacencyMatrix == null) {
            return false;
        }
        int nodeCount = adjacencyMatrix.length;
        int[] visitationStates = new int[nodeCount]; // 0=Unvisited, 1=Visiting, 2=Visited

        for (int i = 0; i < nodeCount; i++) {
            if (visitationStates[i] == 0) {
                if (depthFirstSearch(i, adjacencyMatrix, visitationStates)) {
                    return true;
                }
            }
        }
        return false;
    }

    private static boolean depthFirstSearch(int currentNode, int[][] adj, int[] states) {
        states[currentNode] = 1; // Mark node as in-progress

        for (int neighbor : adj[currentNode]) {
            if (states[neighbor] == 1) {
                return true; // Cycle detected via back-edge
            }
            if (states[neighbor] == 0) {
                if (depthFirstSearch(neighbor, adj, states)) {
                    return true;
                }
            }
        }

        states[currentNode] = 2; // Mark node as fully processed
        return false;
    }
}

#include <iostream>
#include <vector>
using namespace std;
int main() {
    vector<int> a = {1, 2, 3, 4, 5};
    int s = 0;
    for(auto x: a) {
        s += x * x;
    }
    cout << "sum of squares is " << s << endl;
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

/**
 * Computes and prints the sum of the squares of elements in a vector.
 */
int main() {
    const std::vector<int> elements = {1, 2, 3, 4, 5};

    // Accumulate the squares using an elegant lambda expression
    long long sumOfSquares = std::accumulate(elements.begin(), elements.end(), 0LL,
        [](long long accumulator, int value) {
            return accumulator + (static_cast<long long>(value) * value);
        });

    std::cout << "The computed sum of squares is: " << sumOfSquares << std::endl;
    return 0;
}

class FastNode:
    def __init__(self, key, val):
        self.k = key
        self.v = val
        self.nxt = None
        self.prv = None

class LRUCache:
    def __init__(self, cap):
        self.c = cap
        self.d = {}
        self.head = FastNode(0, 0)
        self.tail = FastNode(0, 0)
        self.head.nxt = self.tail
        self.tail.prv = self.head

    def _rm(self, node):
        node.prv.nxt = node.nxt
        node.nxt.prv = node.prv

    def _add(self, node):
        node.nxt = self.head.nxt
        node.prv = self.head
        self.head.nxt.prv = node
        self.head.nxt = node

# Simple python parser script to count keywords
def check_py(fpath):
    try:
        with open(fpath, 'r') as f:
            code = f.read()
            keywords = ['def', 'class', 'import', 'return', 'if', 'for']
            counts = {kw: code.count(kw) for kw in keywords}
            return counts
    except Exception as e:
        print('Failed to read file:', e)
        return {}

import typing

def analyze_python_keywords(file_path: str) -> typing.Dict[str, int]:
    """
    Analyzes a Python file to compute the frequencies of critical keywords.
    Robust exception handling guarantees safety against file access issues.
    """
    target_keywords = ['def', 'class', 'import', 'return', 'if', 'for']
    keyword_frequencies = {keyword: 0 for keyword in target_keywords}

    try:
        with open(file_path, 'r', encoding='utf-8') as source_file:
            file_contents = source_file.read()
            for keyword in target_keywords:
                keyword_frequencies[keyword] = file_contents.count(keyword)
    except IOError as file_error:
        print(f"[ERROR] Failed to open source file at '{file_path}': {file_error}")

    return keyword_frequencies
